#include <iostream>
#include <mysqlx/xdevapi.h>

int main() {
    sql::mysql::MySQL_Connection conn(sql::mysql::AuthenticationLibrary::DefaultAuthenticationFactory());

    if (conn.connect("localhost", "root", "MySecretPass123", "demo")) {
        std::cout << "Connected to MySQL successfully!\n";
        sql::Statement stmt(conn);
        stmt.execute("SHOW DATABASES");
        auto result = stmt.getResult();
        while (result->fetchNext()) {
            std::cout << result->getString(0) << '\n';
        }
    } else {
        std::cerr << "Failed to connect to MySQL: Error code: " << conn.getError().code() << ", Error message: " << conn.getError().what() << '\n';
    }

    return 0;
}